const crypto = require('crypto');
const payload = $input.first().json.body || $input.first().json;

// Limite retry : max 3 tentatives
const retryCount = (payload.retry_count || 0) + 1;
if (retryCount > 3) {
  return [{ json: { abort: true, reason: 'Max retries (3) atteint', original_workflow: payload.workflow_name, retry_count: retryCount } }];
}

const dlqPayload = {
  // Champs alignés sur ismail.webhook.log (Section 15 doc technique)
  source: 'dlq_handler',
  event_type: 'dlq_replay',
  original_workflow: payload.workflow_name || 'unknown',
  original_execution: payload.execution_id || 'unknown',
  error_message: payload.error || 'Erreur inconnue',
  error_code: payload.error_code || 500,  // stocké dans payload JSON
  failed_payload: payload.original_payload || {},
  retry_count: retryCount,
  status: 'received',  // champ réel ismail.webhook.log : received/processed/error
  metadata: {
    timestamp: Math.floor(Date.now() / 1000),
    source: 'n8n_dlq',
    instance: 'automation.targetupconsulting.com'
  }
};

const secret = $credentials.ismail_webhook_secret.secret;
const body = JSON.stringify(dlqPayload);
const signature = 'sha256=' + crypto.createHmac('sha256', secret).update(body).digest('hex');

return [{ json: { abort: false, payload: dlqPayload, hmac_signature: signature, workflow_name: $workflow.name, execution_id: $execution.id } }];

